import React, { useState } from 'react';
import accessService from '../services/accessService';
import { useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
function RequestAccess() {
  const [form, setForm] = useState({ fileId: '', ownerEmail: '', role: 'read', message: '', expiry_time: '', geo_lat: null, geo_lon: null, geo_radius_m: 100 });
  const navigate = useNavigate();
  const submit = async (e) => { e.preventDefault(); try { await accessService.requestAccess(form); alert('Request sent'); navigate('/dashboard'); } catch (e) { alert('Failed'); } };
  const defaultCenter = { lat: 18.5204, lng: 73.8567 };
  const markerIcon = new L.Icon({ iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png', iconSize: [25, 41], iconAnchor: [12, 41], shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png', shadowSize: [41, 41] });
  function LocationPicker() {
    useMapEvents({ click(e) { setForm({ ...form, geo_lat: e.latlng.lat, geo_lon: e.latlng.lng }); } });
    return form.geo_lat != null ? <Marker position={{ lat: form.geo_lat, lng: form.geo_lon }} icon={markerIcon} /> : null;
  }
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-100 via-purple-100 to-blue-50 flex flex-col items-center justify-center p-8">
      <div className="w-full max-w-2xl bg-white rounded-3xl shadow-2xl p-10">
        <div className="flex items-center gap-3 mb-4">
          <span className="text-4xl">🔐</span>
          <h2 className="text-3xl font-extrabold text-purple-700 tracking-tight">Request Access</h2>
        </div>
        <form onSubmit={submit} className="space-y-6">
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">File ID</label>
            <input required placeholder="File ID" value={form.fileId} onChange={e => setForm({ ...form, fileId: e.target.value })} className="w-full p-3 border-2 border-blue-300 focus:border-purple-500 rounded-xl focus:outline-none transition" />
          </div>
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">Owner Email</label>
            <input required placeholder="Owner Email" value={form.ownerEmail} onChange={e => setForm({ ...form, ownerEmail: e.target.value })} className="w-full p-3 border-2 border-blue-300 focus:border-purple-500 rounded-xl focus:outline-none transition" />
          </div>
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">Role</label>
            <select value={form.role} onChange={e => setForm({ ...form, role: e.target.value })} className="w-full p-3 border-2 border-blue-300 focus:border-green-400 rounded-xl focus:outline-none transition">
              <option value="read">🔎 Read</option><option value="download">⬇️ Download</option><option value="share">🔗 Share</option>
            </select>
          </div>
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">Expiry (optional)</label>
            <input type="datetime-local" value={form.expiry_time} onChange={e => setForm({ ...form, expiry_time: e.target.value })} className="w-full p-3 border-2 border-blue-300 focus:border-purple-400 rounded-xl focus:outline-none transition" />
          </div>
          {/* Geofence Section */}
          <div className="pt-4 border-t-2 border-blue-100">
            <h4 className="text-lg font-bold text-blue-600 mb-2 flex items-center gap-2">📍 Geofence (Optional)</h4>
            <div className="mb-2" style={{ height: '220px', width: '100%' }}>
              <MapContainer center={defaultCenter} zoom={10} style={{ height: '100%', width: '100%', borderRadius: 14, overflow: 'hidden', border: '2px solid #cbd5e1' }}>
                <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution="&copy; OpenStreetMap contributors" />
                <LocationPicker />
              </MapContainer>
            </div>
            <div className="flex gap-2">
              <input type="number" min="10" step="10" placeholder="Radius (meters)" value={form.geo_radius_m} onChange={e => setForm({ ...form, geo_radius_m: e.target.value })} className="w-2/3 p-3 border-2 border-blue-300 focus:border-green-400 rounded-xl focus:outline-none transition" />
              <span className="inline-block self-center text-gray-500">meters</span>
            </div>
          </div>
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">Message</label>
            <textarea placeholder="Message (optional)" value={form.message} onChange={e => setForm({ ...form, message: e.target.value })} className="w-full min-h-[60px] p-3 border-2 border-blue-300 focus:border-purple-400 rounded-xl focus:outline-none transition"></textarea>
          </div>
          <button className="bg-blue-600 hover:bg-blue-700 focus:bg-blue-800 text-white px-6 py-3 rounded-2xl shadow-lg font-bold text-lg w-full transition">Send Request</button>
        </form>
      </div>
    </div>
  );
}
export default RequestAccess;
